import{_ as t,o as i,c as a,a2 as s}from"./chunks/framework.DGS7qFRZ.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"playstore-flow","text":"Google Play Console from your terminal","tagline":"Manage Android listings, in-app products, and subscriptions from YAML files. CLI + bundled MCP server.","actions":[{"theme":"brand","text":"Get started","link":"/getting-started"},{"theme":"alt","text":"View on GitHub","link":"https://github.com/zmij/playstore-cli"}]},"features":[{"icon":"📝","title":"YAML-first","details":"Pull every per-language listing, one-time product, subscription base plan, and offer into committed YAML. Edit in your editor; sync back."},{"icon":"🔄","title":"Two-way reconcile","details":"Field-level diff with paths like `subscriptions/my_sub/base_plans/monthly/regional_configs/DE/...`. Pull updates without clobbering local edits."},{"icon":"🤖","title":"Bundled MCP server","details":"Same client code, exposed over stdio. Any MCP-aware agent (Claude Code, Cursor, Cline, Windsurf) can read and update live Play state."},{"icon":"💰","title":"Price migrations + state lifecycle","details":"Migrate existing subscribers via `batchMigratePrices`. Activate / deactivate base plans and offers from the CLI. Dry-run by default."},{"icon":"⚡","title":"One install, two binaries","details":"Single `npm install`, two binaries (`playstore` + `playstore-mcp`). Configurable for any Android project via three independent path knobs."},{"icon":"🆕","title":"Built on monetization.*","details":"Wraps the new `monetization.onetimeproducts` / `subscriptions` APIs (the legacy `inappproducts` endpoint that\'s dead for new accounts)."}]},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":1782052843000}'),n={name:"index.md"};function l(o,e,r,p,d,h){return i(),a("div",null,[...e[0]||(e[0]=[s('<h2 id="what-it-does" tabindex="-1">What it does <a class="header-anchor" href="#what-it-does" aria-label="Permalink to &quot;What it does&quot;">​</a></h2><p><code>playstore-flow</code> puts your Android store presence under version control. Instead of clicking through the Play Console&#39;s per-language tabs and per-product editors to update copy, prices, or release notes, you pull live state into committed YAML, edit it in your editor, and sync it back through normal PR review.</p><p>The bundled <code>playstore-mcp</code> server exposes the same client code over stdio so any MCP-aware agent — Claude Code, Cursor, Windsurf, Cline, Continue, Zed — can read and update live Play state without shelling out.</p><h2 id="quick-install" tabindex="-1">Quick install <a class="header-anchor" href="#quick-install" aria-label="Permalink to &quot;Quick install&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> playstore-flow</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># or, from a checkout (the GitHub repo is still `playstore-cli` —</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># only the npm package name has been rebranded to `playstore-flow`):</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/zmij/playstore-cli.git</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> playstore-cli</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> link</span></span></code></pre></div><p>Then see <a href="/playstore-cli/getting-started">Get started</a> for the first-run walkthrough.</p><h2 id="in-production" tabindex="-1">In production <a class="header-anchor" href="#in-production" aria-label="Permalink to &quot;In production&quot;">​</a></h2><blockquote><p>I built this to manage <a href="https://lazy-sudoku.online" target="_blank" rel="noreferrer">Lazy Sudoku</a>&#39;s Play Console — 14-locale listings, plus the full IAP catalogue (9 one-time products + 3 subscriptions with monthly/annual base plans) committed as YAML and synced via <code>playstore iap sync</code>. The bundled MCP server lets Claude Code read live Play state during release prep without me leaving the terminal. Everything goes through PRs; nothing happens by clicking through the Play Console.</p><p>— <em>Sergei Fedorov, <a href="https://lazy-sudoku.online" target="_blank" rel="noreferrer">Lazy Sudoku</a></em></p></blockquote><p>Using playstore-flow somewhere? <a href="https://github.com/zmij/playstore-cli/blob/master/README.md" target="_blank" rel="noreferrer">Open a PR</a> adding yourself to the Adopters section in the README.</p>',9)])])}const k=t(n,[["render",l]]);export{u as __pageData,k as default};
